UPDATE sites SET horario_en = 'Open on event days (Fair concerts, Ajazzgo festival, cinema); The upper park is public access.', tarifa_en = 'Public events are usually free.', descripcion_en = 'Perched on the western slope of Cali, very close to San Antonio, Los Cristales is one of the city''s most beloved stages: a large open-air amphitheater whose acoustic shell and terraced stands form the perfect setting for concerts, movies under the stars and festivals. In addition to the stage, the complex has dressing rooms, offices and, in its upper part, a large park with a water source, flora and fauna especially rich in birds. Salsa, rock, classical music, Andean music, jazz and chirimía have passed through its stages.', datos_historicos_en = 'The famous acoustic shell was built in 1986, under the management of Hernando Botero O''Byrne. Designed by architect Sigifredo Rojas and calculated by engineer Camilo Niño Vélez. In 2025, the title of the property was achieved in favor of the District.', datos_curiosos_en = ARRAY['The constructed area of ​​the theater is around 3,920 m²; The theoretical capacity is estimated at 15,000 people.', 'The stage measures 10 meters wide inside and opens 25 meters to the outside.', 'Its upper part functions almost like a small eco-park, with water sources and birds.']::text[] WHERE id = 's121';
UPDATE sites SET horario_en = 'Public access campus during institution hours; The Mario Carvajal Library and the green areas can be visited according to regulations.', tarifa_en = 'Not applicable.', descripcion_en = 'To the south of Cali, between Pasoancho Avenue and the Pance Hills, lies one of the largest and most beautiful university campuses in Colombia: the Ciudad Universitaria Meléndez of the Universidad del Valle. On a million square meters that were previously cane fields, the "Univalle" built a city-park with an artificial lake, groves and views of the Farallones. It is the main higher education institution in southwestern Colombia, public and research, with more than 30,000 students, and its emblem—the owl—presides over an academic and cultural life that has marked the history of the city.', datos_historicos_en = 'Created on June 11, 1945 by Ordinance 12. In 1954 it changed its name to Universidad del Valle. Since 1965, the Meléndez University City has been built. In 1971 it served as the Olympic village for the Pan American Games.', datos_curiosos_en = ARRAY['The architectural design was coordinated by architects Jaime Cruz and Diego Peñalosa.', 'The university''s symbol is the owl, and its central library is named after Mario Carvajal.', 'Much of the campus remains deliberately unbuilt, as a green reserve.']::text[] WHERE id = 's122';
UPDATE sites SET horario_en = 'Functions according to billboard (usually from Thursday to Sunday); administrative care M–F.', tarifa_en = 'Ticket office according to function.', descripcion_en = 'Cali Teatro operates in a house in the traditional San Antonio neighborhood, one of the largest and best-equipped independent theaters in the city. The Cali Teatro Stage Foundation was born in 1989 and, from its own headquarters, has built a space with capacity for about 150 spectators in the stalls and box, with an anteroom, cafeteria and a permanent exhibition of graphic material that bears witness to its career. For about ten months a year it programs theater seasons with its regular cast and guest groups from the city, the country and abroad.', datos_historicos_en = 'Foundation of the Cali Teatro Stage Foundation in 1989. It has performed more than 38 productions throughout its history. In 2021 the "Alternative Theater Exhibition but of Good Good" festival is created.', datos_curiosos_en = ARRAY['Its 150-seat room is cinema-type, and the stage has a pit or stage trap.', 'Much of its recent programming addresses sensitive and contemporary topics: mental health, eating disorders, LGBTIQ+ population.']::text[] WHERE id = 's69';
UPDATE sites SET horario_en = 'Functions according to billboard (usually weekends).', tarifa_en = 'Ticket office, with a discount for students.', descripcion_en = 'In an old house in the San Fernando neighborhood, adapted as a house-theater, beats Domus Teatro: an intimate room-studio, one of those designed not to fill large capacities but to form an audience. Founded in 1994 by Manuel Sierra and Luz Stella Gil, the Domus Teatro Foundation has since offered a permanent cultural program that includes theater, music, dance, pictorial exhibitions and conversations. Its rooms are small—for 50 or 70 spectators—with the idea of ​​cultivating, show by show, the spectators that Cali needs.', datos_historicos_en = '1994: foundation of Domus Teatro by Manuel Sierra and Luz Stella Gil. Late 90s: the hall promotes a Festival of Halls in concert. It has maintained its own repertoire and continuous programming for more than 31 years (as of 2025).', datos_curiosos_en = ARRAY['Domus is defined as a "studio-room": training and creation are as important as the exhibition.', 'He has invited important groups such as Ditirambo (Bogotá).', 'Its philosophy is summarized by a phrase from its founders to the artists they invite: "Come on, let''s study."']::text[] WHERE id = 's68';
UPDATE sites SET horario_en = 'Friday and Saturday 7:30 p.m. m.; family season Sundays 4:00 p.m. m.', tarifa_en = 'Ticket office according to function.', descripcion_en = 'The Teatro del Presagio was born in 2005 as a professional theater group formed by graduates in dramatic art from Cali, dedicated to research, creation and stage production. After almost ten years of itinerant work, in November 2014 he opened his own room—a cultural space—in the Granada neighborhood, an area of ​​cafes, restaurants and antique shops that until then had no real setting for the arts. Their proposal flees from large commercial spectacles: it is built, as they themselves say, "from astonishment and the brief emotions that arise between the light."', datos_historicos_en = '2005: the group is formed, with dramaturgy and direction by Diego Fernando Montoya. \nNovember 2014: inaugurates its own headquarters in the Granada neighborhood. \nSince 2019: holds the Queer Art Meeting, with a rich artistic and academic agenda.', datos_curiosos_en = ARRAY['Its usual programming is Friday and Saturday at 7:30 p.m. m., with a family season on Sundays at 4:00 p.m. m.', 'It has a program dedicated to forming new audiences among children and young people in educational institutions.']::text[] WHERE id = 's70';
UPDATE sites SET horario_en = 'Seasonal microtheater, usually from Thursday to Saturday, between 8:00 and 11:00 p.m. m.', tarifa_en = 'Box office by performance; separate food and drink consumption.', descripcion_en = 'Espacio T brought to Cali a format that did not exist in the city: microtheater. In a beautiful old house in the San Antonio neighborhood, its bedrooms were converted into minimal rooms where three pieces of about 15 minutes are presented, in spaces of 15 m², for just 15 spectators each. The plays rotate every half hour between 8 and 11 at night, and the experience is completed with a restaurant and a bar serving craft drinks: theater and after-dinner meals in the same plan. It was inaugurated on December 3, 2015 by Leandro Fernández—a Cali actor and director based in Miami—and his wife Ángela María Osorio, who brought the concept from their living room in that city.', datos_historicos_en = 'December 3, 2015: opening of Espacio T in the historic center. \n2023: opening of La Carpa T, its patio stage for long format.', datos_curiosos_en = ARRAY['The formula that defines it: 15-minute works, for 15 people, in rooms of 15 square meters.', 'Leandro Fernández, its founder, is the brother of some of the creators of the TEC (Teatro Experimental de Cali).', 'Between shows and shows, old salsa usually sounds.']::text[] WHERE id = 's123';
UPDATE sites SET horario_en = 'Performances usually Friday and Saturday, 7:30 p.m. m.', tarifa_en = 'Ticket office according to function.', descripcion_en = 'In a house declared Architectural-Urban Heritage of Cali, in the heart of the San Antonio neighborhood, the Teatro La Concha operates: a performing space at the service of the Ibero-American artistic community. Founded in 2007, it is part of the "Yolanda García Reina" Theater and Arts Foundation and has a medium-format room, an exhibition room and an alternate room for rehearsals and small-format productions. The house also keeps a layer of Cali memory: it permanently houses the exhibition by the plastic artist Carlos Zuluaga about Jovita Feijóo, one of the city''s most endearing popular characters.', datos_historicos_en = '2007: foundation of the La Concha Theater, within the "Yolanda García Reina" Theater and Arts Foundation. \nIts headquarters is a house in the historic center cataloged as Architectural-Urban Heritage of Cali. \nHe has developed co-productions (for example, with Entropía Teatro) and actively participates in the Cali Independent Theater Network.', datos_curiosos_en = ARRAY['In the same house you can visit the permanent exhibition about Jovita Feijóo, a mythical figure of "old Cali".', 'During the pandemic it was one of the first venues in Cali to enable a web platform to transmit its works.']::text[] WHERE id = 's118';
UPDATE sites SET horario_en = 'Tuesday to Sunday, 8:00 a.m. m.–5:00 p.m. m. (Monday closed).', tarifa_en = 'Free admission.', descripcion_en = 'In the heart of commune 22, south of the city, the Lago de las Garzas Ecopark is an unexpected oasis: a wetland and one of the few remnants of tropical dry forest left in Cali, fed by the waters of the Pance River. Herons, tinguas, turtles, squirrels, iguanas, butterflies and dozens of species of resident and migratory birds coexist around its mirror of water, which come to rest on their journey between continents. There is a wooden dock for bird watching, ecological trails and an environment designed for "passive recreation": observing, breathing and disconnecting without disturbing the ecosystem.', datos_historicos_en = 'It was born from a tragedy: the crash of American Airlines Flight 965 in 1995. In 1996, recovery work began and 400 trees were planted in memory of the victims. In 2002 it was included in the Territorial Planning Plan.', datos_curiosos_en = ARRAY['It has an approximate area of ​​4.7 hectares, with a lake of about 0.8 hectares.', 'It is home to more than 80 species of birds and more than 70 species of butterflies.', 'It receives around 60,000 visitors a year.']::text[] WHERE id = 's38';
UPDATE sites SET horario_en = 'Functions and workshops according to schedule (usually weekends).', tarifa_en = 'Ticket office according to function; workshops with registration.', descripcion_en = 'AESCENA (National Performing Arts) is a professional artistic foundation that, for more than two decades, has operated both as a school and as an independent venue. In its "Casa Aescena" it offers permanent theater programming for adults, young people and children - comedy, drama, experimental -, and a line of comprehensive training in interpretation, dramaturgy and body expression by recognized teachers of the local scene. Its team is interdisciplinary: it adds sociology, law, social communication and pedagogy to art.', datos_historicos_en = 'It has been working continuously as an independent school and venue for more than two decades. \nIts Casa Aescena has a room for about 50 people and a 4.80 × 5.60 m stage, as well as spaces for workshops and rehearsals.', datos_curiosos_en = ARRAY['Organize open spaces such as the "Actoral Jam", for actors and non-actors who want to improvise without a script.', 'His work articulates several disciplines of knowledge around the scene.']::text[] WHERE id = 's124';
UPDATE sites SET horario_en = 'Functions and workshops on Saturdays.', tarifa_en = 'The entrance is paid with food (an egg, rice, panela, tuna...).', descripcion_en = 'In a three-story house painted orange, in the El Poblado I neighborhood, in the heart of the Aguablanca District, is the only theater in eastern Cali. Casa Naranja is a story of stubbornness and love for art: it was built, brick by brick, by John Jairo Perdomo, community leader and performing artist, so that children and young people from one of the hardest hit areas of the city would have a place to discover their talent. Here the entrance has an unusual and beautiful price: you pay with food. An egg is an entry; two eggs, two; Half a pound of rice or sugar, or a panela, are worth three; a tuna, for four. What is collected feeds the artists and the community.', datos_historicos_en = 'Its roots are in the "Colectivo Teatral Espejos", around 1998; The room as such has been operating since 2004. \nIt is estimated that more than 7,600 children and young people have passed through its boards, trained for free; Every year more than 400 pass. \nIt has the support of Compromiso Valle, the Fanalca Foundation, Bolívar Davivienda, the Chamber of Commerce, ProPacífico and the Mayor''s Office, among others.', datos_curiosos_en = ARRAY['Its philosophy is "vitamin C": Christ, trust, culture, carnival, affection, coexistence, community and celebration. Hence the name.', 'Their motto is "We are all others."', 'One of its flagship projects is the "Parade of Light", every August 7 through the streets of the east (it has brought together up to 800 participants). It was born after the murder of six young people, as an act to bring light and honor the lives of the boys in the sector.', 'On its terrace it keeps giant dolls of Gato de Tejada, Jovita and the chontaduros seller, destined for a future Museum of Old Cali.']::text[] WHERE id = 's132';
UPDATE sites SET horario_en = 'According to academic calendar.', tarifa_en = 'public training; programs with tuition depending on the institution.', descripcion_en = 'The Popular Institute of Culture—the IPC—is one of the institutions that has most marked the artistic life of Cali. It was born at the initiative of the Municipal Council on December 18, 1947, in the full context of the "Liberal Republic", with a pioneering mission: to provide artistic-cultural training to the popular sectors of the city, understanding art as a tool to educate and transform social reality. Over time, it consolidated four schools—Plastic Arts, Dance, Music and Theater—through which generations of Cali artists, teachers and cultural managers have passed.', datos_historicos_en = 'December 18, 1947: creation by Agreement No. 450 of the Municipal Council. \n2011: it becomes a Decentralized Public Establishment, linked to the Ministry of Education (Agreement 0313), with its own autonomy and assets. \n2023: upon turning 76, the Ministry of Education approves the creation of the University Institution of Popular Cultures and Arts IPC (IUIPC), the first of its kind in the country, in the rehabilitated Coltabaco Building.', datos_curiosos_en = ARRAY['In the beginning it also taught national history, civic education, geography, hygiene and urbanity to the working classes.', 'Its publication and its meetings have documented, among other memories, that of the hillside ("Siloé resiste"), linking with the Popular Museum of Siloé.']::text[] WHERE id = 's133';
UPDATE sites SET horario_en = 'Park open all day.', tarifa_en = 'Free.', descripcion_en = 'A delicious open-air art gallery on the banks of the Cali River. Presided over by the monumental ''Cat of the River'', a bronze work by master Hernando Tejada, this green area became the home of his ''brides'': a collection of more than 15 cats sculpted and painted by renowned Colombian artists (such as Maripaz Jaramillo, Omar Rayo, etc.). Each cat has a unique personality, history and design. It is a colorful, artistic and refreshing walk. El Gato del Río, by Hernando Tejada, was installed on July 3, 1996; ''Las Gatas del Río'' (sculptures made by different artists) were added in 2006.', datos_historicos_en = 'Bronze sculpture by Hernando Tejada, inaugurated on July 3, 1996 on the banks of the Cali River. In 2006, "the cat''s girlfriends/cats" were added, sculptures made by various artists, promoted by the Tejada family and the Chamber of Commerce.', datos_curiosos_en = ARRAY['It weighs around three tons and was cast in Bogotá.', 'Each of the "cats" was decorated by a different artist.', 'It is one of the most visited and photographed monuments in the city.']::text[] WHERE id = 's8';
UPDATE sites SET horario_en = 'Performances on Sundays; weekdays for schools and groups with prior reservation.', tarifa_en = 'General admission approx. $15,000; free for the children of the neighborhood.', descripcion_en = 'Twenty minutes from the city, in the Los Limones neighborhood of the La Castilla district, west of Cali, there is a real castle: two medieval-style towers, a green area and open sky, made for children to have their puppet theater. It is the Sol y Luna Castle, the only castle-shaped room in a rural area of ​​the city. It was dreamed and built by maestro Reynel Osorio Torres – puppeteer, actor and teacher with more than 45 years of experience – when he retired from the Popular Institute of Culture and invested his savings in building, with his family, this space for early childhood.', datos_historicos_en = 'Founded in 2002 by teacher Reynel Osorio, together with his wife Luz Myriam García Franco and his daughter Melisa Osorio García. \nHe has participated in departmental, national and international puppet festivals.', datos_curiosos_en = ARRAY['It has inclusion programs ("We are diverse with rights") for children in situations of disability, social risk or illness: with blind children, for example, they let the dolls be touched before the performance to recognize them by their voice.', 'Ducks, chickens, rabbits, pigeons and even a sheep named Cornelia, who asks for guavas, live on campus.', 'Children on the sidewalk always get in for free.']::text[] WHERE id = 's134';
UPDATE sites SET horario_en = 'Functions and workshops according to schedule (weekends).', tarifa_en = 'Ticket office according to function.', descripcion_en = 'The Infinito Theater Collective is one of the most moving projects on the Cali scene: the first – and for a long time only – theater training school for people with disabilities in the country. Founded in 2005 by teacher Harold Molina (IPC graduate) and Paula Macía, the CTI integrates children, young people and adults, and especially actors and actresses with Down Syndrome, in professional level productions. Their goal is to demonstrate, on stage, that far from the idea of ​​"disability" there is enormous talent to show.', datos_historicos_en = 'December 2, 2005: constitution of the Infinito Teatral Collective Artistic and Cultural Foundation. \nHe has built a repertoire of his own works (such as *Mío Amor*) that have represented the city inside and outside of Cali. \n2023: thanks to the Public Entertainment Law (LEP) and the management of the Ministry of Culture, it finally opened its own venue. \n2025: celebration of 20 years of work.', datos_curiosos_en = ARRAY['It is recognized as the first and only theater training school for the disabled population in the country.', 'Its director, Harold Molina, trained at the IPC—another thread that links this institution to the city''s performing arts circuit.']::text[] WHERE id = 's135';
UPDATE sites SET horario_en = 'Wednesday and Thursday 6:00 p.m. m.–1:00 a.m. m.; Friday and Saturday 6:00 p.m. m.–3:00 a.m. m.', tarifa_en = 'Cover ~$10,000.', descripcion_en = 'On the mythical Calle 5—the one that Grupo Niche names in "Cali Ají"—is the salsoteca where the music lover and the private dancer share the same dance floor. La Topa Tolondra opened in 2011 almost by chance: it started with a table and a refrigerator, and its name comes from the Valle del Cauca saying "a la topa tolondra", which is doing things on the run, without a plan. From that improvisation came one of the temples of the Cali rumba. \n\nIt''s not just commercial salsa that sounds here: bugalú, pachanga, guaguancó, bolero and collectible Afro-Latin downloads play, with a music library that respects the roots of the genre. He teaches dance classes during the week and brings together people from Cali and foreigners around the dance floor. It is the place where it is understood that salsa here is not a show for tourists, but rather a daily occupation.', datos_historicos_en = 'It started as a small bar on 5th Street and grew to become the current temple in front of Jovita Park. It opened in 2011.', datos_curiosos_en = ARRAY['It is on Calle 5, the same one that Grupo Niche mentions in "Cali Ají".', 'Many visitors take their first dance steps here, in classes prior to the party.', 'Their selection includes Los Hermanos Lebron, Ángel Canales and Sonora Ponceña.']::text[] WHERE id = 's7';
UPDATE sites SET horario_en = 'Gardens open to the public Monday to Sunday, 9:00 a.m. m.–4:00 p.m. m. (continuous day).', tarifa_en = 'Free entry.', descripcion_en = 'In the center-north of the city, the Central Cemetery is much more than a cemetery: it is a living archive where a good part of the memory of Cali rests. Officially installed at this point around 1852, it was the third location of the city''s Catholic cemetery - the first was where Cayzedo Square is today and the second in the current San Nicolás Park. And the land has even deeper roots: it was the ancient indigenous settlement of San Diego de Alcalá de Yanaconas, from where the Yanaconas were transferred in 1778. Between its republican funerary architecture and its chapel, one of the oldest in the city, it runs like an avenue of Cali history.', datos_historicos_en = 'Around 1852, the current land was awarded and the cemetery was installed there (third location of the Cali Catholic cemetery). \nThe site was, in colonial times, the indigenous settlement of San Diego de Alcalá de Yanaconas. \nIt has been investigated by specialists in funerary heritage, such as the architect Ricardo Hincapié (Universidad del Valle).', datos_curiosos_en = ARRAY['Next to the marble mausoleums live "popular saints": tombs converted into places of devotion, decorated with flowers, letters, photos and offerings.', 'Jovita Feijóo''s tomb links this place with the La Concha Theater (which dedicates an exhibition to her) and with the old Cali dolls from Casa Naranja.', 'The presence of the Yanacona in its origin connects the site with the Popular Museum of Siloé, which also narrates that indigenous root of the city.']::text[] WHERE id = 's127';
UPDATE sites SET horario_en = 'Open daily; The plaza days—with more variety and atmosphere—are Tuesday, Thursday and Saturday, especially in the morning.', tarifa_en = 'Free entry; separate consumption.', descripcion_en = 'In the Alameda neighborhood, in the center of Cali, there is a market that is much more than a place to shop: it is a trip from the Andes to the Pacific in a few steps. The Alameda Gallery - or Alameda Market Square - is a labyrinth of colors and aromas where exotic fruits, fresh vegetables, meats, flowers and, above all, the best traditional cuisine of the Valley and the Colombian Pacific coexist. Here the cooks from Buenaventura—inheritors of culinary knowledge that dates back to the times of slavery—serve fish sancocho with coconut milk, shrimp ceviche, sudados, stuffed meat, and tamale on huge plates. To walk through it is to come into contact with the popular, happy and talkative spirit of the Cali people.', datos_historicos_en = 'The Alameda neighborhood was founded in October 1930. The Market Square has its origins around 1947. Around 1970, most of the current building was built. Since 1994 it has been managed by ASOALAMEDA.', datos_curiosos_en = ARRAY['The first sellers spread their products on the floor.', 'Among its treasures are little-known fruits: strawberry tree, chachairú, mangosteen, sapote, arazá, cherimoya.', 'There are ''food tours'' that leave from San Antonio and have Alameda as their star stop.']::text[] WHERE id = 's9';
UPDATE sites SET horario_en = 'Thursday to Saturday, approx. 8:00 p.m. m.–3:00 a.m. m. (Thursday salsa and bachata; Friday taxi dancer; Saturday Cali rumba).', tarifa_en = 'Cover depending on the night (from ~$5,000).', descripcion_en = 'Classic among classics, Tin Tin Deo is one of the most respected temples of salsa in Cali: a place where the genre is listened to with the same devotion with which it is danced. Its name – taken from a Dizzy Gillespie song – already announces the cult level of its musical selection, and its track is a pilgrimage point for dancers from all over the world. \n\nWith decades of experience, it has sustained a lifelong club atmosphere where the connoisseur and the fan coexist. It is a must-see stop for anyone who wants to understand why Cali is called the world capital of salsa, beyond the tourist spectacle.', datos_historicos_en = 'Its name comes from the famous song by Chano Pozo and Dizzy Gillespie, marking its Latin Jazz influence. Founded in 1985.', datos_curiosos_en = ARRAY['Its name comes from a composition by jazz trumpeter Dizzy Gillespie.', 'It is usually cited among the most emblematic salsotecas in the city.']::text[] WHERE id = 's29';
UPDATE sites SET horario_en = 'Works for young people and adults: Saturdays 7:30 p.m. m.; Family Functions: Sundays 11:00 a.m. m. (with prior registration); concerts: one Friday a month, 7:30 p.m. m. (programming varies; consult networks).', tarifa_en = 'Ticket office according to function (Concerted Room).', descripcion_en = 'In 1973, a group of students from different majors at the Universidad del Valle began to meet in their free time to do what they were most passionate about: acting. In a Cali that only had TEC, that university "patch" led by Orlando Cajamarca became Esquina Latina, today one of the most important theater organizations in southwestern Colombia, with more than fifty years of artistic stubbornness. \n\nBut what distinguishes Esquina Latina is not only its theater in the Tejares neighborhood of San Fernando: it is its conviction that theater is not for the elites. Through the "Youth, Theater and Community" program, active since 1987, it has brought theater to the communes of the east and the hillside of Cali and to municipalities hit by the conflict, training theater entertainers and using the stage as a tool of peace. Here the word "cultural" recovers its social meaning.', datos_historicos_en = 'It was born in 1973 as a student group at the Universidad del Valle and was consolidated as an independent foundation. Founded in 1973 by Orlando Cajamarca.', datos_curiosos_en = ARRAY['Its "Youth, Theater and Community" program has been working since 1987 in vulnerable communes and municipalities of the Valley and northern Cauca.', 'Thousands of people from popular sectors have gone on stage for the first time thanks to their Popular Theater Network.', 'Its founding director, Orlando Cajamarca, is a doctor, playwright and nationally and internationally awarded director.']::text[] WHERE id = 's42';
UPDATE sites SET horario_en = 'The last Friday of each month (doors open 7:00 p.m.; show starts around 9:30 p.m.); special editions at the Cali Fair (December). Entry only for those over 18 years of age.', tarifa_en = 'Ticket office by areas and locations (advance purchase through TuBoleta and official channels).', descripcion_en = 'In 2006, when Cali still carried the memory of its hardest times, four women—Andrea Buenaventura, former director of the Cali Fair, along with Eleonora Barberena, Liliana Ocampo and Ángela María Gallo—set out a delirious equation: bringing the salsa of the neighborhoods to the European cabaret format, adding circus and live orchestra. They started with a small platform that today is embarrassing in photos; They ended up creating one of the biggest salsa shows in the world. \n\nUnder the Delirio Tent, on the last Friday of each month, the speed of Cali salsa meets acrobats, its own orchestra and a stage performance that has toured more than twenty countries. Behind the brilliance is a foundation with a social purpose: it uses dance and music to transform the lives of young people from sectors affected by violence. It is Cali converted into a creative industry and pride.', datos_historicos_en = 'The Delirio Foundation also operates the Paseo de la Aurora theme park, Sat–Sun 12:00 noon–8:00 p. m.', datos_curiosos_en = ARRAY['It has performed hundreds of performances in more than 20 countries and has been seen by more than half a million people.', 'Their music is performed live by the Boranda Orchestra; The circus is provided by the Circo Herencias company.', 'Its social program "Paso Firme" works with young people from training centers in vulnerable contexts.']::text[] WHERE id = 's97';
UPDATE sites SET horario_en = 'open area; strong nightlife.', tarifa_en = 'Free (consumptions apart).', descripcion_en = 'Traditional park in the San Fernando neighborhood, whose name comes from a sculpture of a dog installed there; Over the years it became one of the main gastronomy and party areas in Cali.', datos_historicos_en = 'The statue of Teddy the dog was installed in 1970 by Víctor Alberto Delgado Mallarino, in a traditional park in the San Fernando neighborhood that, over time, became a gastronomy and nightlife area.', datos_curiosos_en = ARRAY['The park was previously called "Heart Park" because of its shape.', 'Under the statue rest the remains of the dog Teddy.', 'It is close to the salsotecas on Calle 5 and Loma de la Cruz.']::text[] WHERE id = 's24';
UPDATE sites SET horario_en = 'Tuesday to Friday, 9:00 a.m. m.–5:00 p.m. m.; Saturdays, 10:00 a.m. m.–5:00 p.m. m. (closed Sundays and Mondays).', tarifa_en = 'Free entry.', descripcion_en = 'Under the administration of the Bank of the Republic, in the historic center, the Calima Gold Museum preserves the brilliance of the cultures that inhabited this valley thousands of years before Cali had a name. Its collection brings together pieces of goldsmithing, ceramics, stone, wood and shell from the Ilama, Yotoco and Sonso societies - grouped under the generic name of Calima culture -, people who were exceptional farmers and, above all, goldsmiths of a skill that still baffles today. \n\nTo travel through it is to understand that the territory we walk on today had a symbolic and technical density prior to any colonial plaza. The museum works with “pedagogical animators” instead of guides, lends educational kits to schools and maintains animations and exhibitions so that the pre-Hispanic past does not feel distant but rather its own.', datos_historicos_en = 'Inaugurated in 1991 as part of the country''s network of gold museums. Inaugurated on May 9, 1991.', datos_curiosos_en = ARRAY['Its collection includes pieces of goldsmithing and pottery up to 2,000 years old from the Ilama, Yotoco and Sonso cultures.', 'In the Calima area, northwest of Cali, archeology has recovered more than 9,000 years of human history.', 'It lends “teaching suitcases” to educational institutions to set up small exhibitions in the classroom.']::text[] WHERE id = 's10';
